import UIKit

class UniversalLinkHandler {
    static func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard let url = userActivity.webpageURL else { return false }
        
        let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
        
        switch components?.path {
        case "/profile/\d+":
            let profileId = Int((components?.path.replacingOccurrences(of: "/profile/", with: "")) ?? "") ?? 0
            let vc = ProfileViewController(profileId: profileId)
            app.windows.first?.rootViewController?.present(vc, animated: true, completion: nil)
        case "/payment/confirm":
            let vc = PaymentConfirmViewController()
            app.windows.first?.rootViewController?.present(vc, animated: true, completion: nil)
        case "/admin/settings":
            let vc = AdminSettingsViewController()
            app.windows.first?.rootViewController?.present(vc, animated: true, completion: nil)
        default:
            return false
        }
        
        return true
    }
}

extension UIApplication {
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        return UniversalLinkHandler.application(self, continue: userActivity, restorationHandler: restorationHandler)
    }
}